#include "layer_norm_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

// UB budget model:
// For each row of normalizedSize floats:
//   - x row: normalizedSize floats
//   - weight row: normalizedSize floats (loaded once per core)
//   - bias row: normalizedSize floats (loaded once per core)
//   - y row: normalizedSize floats
//   - temp for mean/variance reduction: normalizedSize floats
// Total per row: 5 * normalizedSize floats = 20 * normalizedSize bytes
// Additional overhead for squares, maybe 1 extra row buffer => 6 * normalizedSize
// Conservatively: 6 * normalizedSize bytes per row.
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024; // per core
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t MAX_TILE_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    LayerNormCustomTilingData tiling;
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *epsilon = attrs->GetAttrPointer<float>(0);

    uint32_t totalLength = static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetShapeSize());
    uint32_t normalizedSize = static_cast<uint32_t>(context->GetInputShape(1)->GetOriginShape().GetShapeSize());

    // Ensure normalizedSize > 0
    if (normalizedSize == 0) return ge::GRAPH_FAILED;

    // Compute rows in total
    uint32_t rows = totalLength / normalizedSize;
    if (rows * normalizedSize != totalLength) return ge::GRAPH_FAILED; // sanity

    // Compute rows per tile based on UB budget
    uint32_t ubPerRow = 6 * normalizedSize * sizeof(float); // bytes
    uint32_t maxRows = UB_BUDGET_BYTES / ubPerRow;
    if (maxRows < 1) maxRows = 1;
    uint32_t rowsPerTile = maxRows;
    // Cap total elements per tile
    if (rowsPerTile * normalizedSize > MAX_TILE_ELEMS)
        rowsPerTile = AlignDown(MAX_TILE_ELEMS, normalizedSize) / normalizedSize;
    if (rowsPerTile < 1) rowsPerTile = 1;

    uint32_t tileLen = rowsPerTile * normalizedSize;

    // BlockDim: one tile per block, but limit
    uint32_t numTiles = CeilDiv(rows, rowsPerTile);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_normalizedSize(normalizedSize);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_epsilon(*epsilon);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());
    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    gert::Shape *y_shape = context->GetOutputShape(0);
    *y_shape = *x_shape;
    return GRAPH_SUCCESS;
}

